PHI: float = 3.14


@dataclass(frozen=True)
class Lingkaran:
    """Merepresentasikan sebuah lingkaran."""

    jari_jari: float

    def __post_init__(self) -> None:
        if self.jari_jari <= 0:
            raise ValueError("Jari-jari harus lebih dari 0")

    def luas(self) -> float:
        """Mengembalikan luas lingkaran."""
        return PHI * self.jari_jari ** 2


