from decimal import Decimal, InvalidOperation


def celcius_ke_fahrenheit(celcius) -> Decimal:
    """Konversi Celcius ke Fahrenheit dengan presisi Decimal.

    Args:
        celcius: suhu dalam Celcius (angka atau string angka).

    Returns:
        Decimal suhu dalam Fahrenheit.
    """
    try:
        c = Decimal(str(celcius))
    except InvalidOperation as exc:
        raise ValueError(f"celcius tidak valid: {celcius}") from exc
    if c < Decimal("-273.15"):
        raise ValueError("celcius tidak boleh di bawah nol mutlak")
    return c * Decimal("9") / Decimal("5") + Decimal("32")


