def balik_string(kata):
    """Membalik string menggunakan teknik two-pointer."""
    huruf = list(kata)
    kiri, kanan = 0, len(huruf) - 1
    while kiri < kanan:
        huruf[kiri], huruf[kanan] = huruf[kanan], huruf[kiri]
        kiri += 1
        kanan -= 1
    return "".join(huruf)

