def balik_string(kata: str) -> str:
    """Membalik string menggunakan pendekatan iteratif dengan deque untuk efisiensi O(1) di kedua ujung."""
    from collections import deque
    dq = deque(kata)
    hasil = []
    while dq:
        hasil.append(dq.pop())
    return "".join(hasil)


