def faktorial(n):
    """Faktorial iteratif dengan memoization sederhana menggunakan dictionary."""
    cache = {0: 1, 1: 1}
    def hitung(k):
        if k in cache:
            return cache[k]
        cache[k] = k * hitung(k - 1)
        return cache[k]
    return hitung(n)

