def faktorial(n: int) -> int:
    """Faktorial iteratif dengan pendekatan divide and conquer untuk n besar (mengurangi kedalaman perkalian besar)."""
    if n < 0:
        raise ValueError("n tidak boleh negatif")
    if n <= 1:
        return 1
    angka = list(range(2, n + 1))
    def kali(lst):
        if len(lst) == 1:
            return lst[0]
        tengah = len(lst) // 2
        return kali(lst[:tengah]) * kali(lst[tengah:])
    return kali(angka)


