def faktorial(n: int) -> int:
    """n! menggunakan algoritma divide-and-conquer untuk performa lebih baik pada n besar."""
    if not isinstance(n, int) or n < 0:
        raise ValueError("n harus bilangan bulat non-negatif")
    if n <= 1:
        return 1

    def kali_rentang(awal: int, akhir: int) -> int:
        if awal > akhir:
            return 1
        if awal == akhir:
            return awal
        tengah = (awal + akhir) // 2
        return kali_rentang(awal, tengah) * kali_rentang(tengah + 1, akhir)

    return kali_rentang(2, n)


