def find_max(numbers):
    """Find max via single-pass comparison; explicit and allocation-free."""
    it = iter(numbers)
    try:
        maksimum = next(it)
    except StopIteration:
        raise ValueError("numbers must not be empty")
    for n in it:
        if n > maksimum:
            maksimum = n
    return maksimum

