def find_max(numbers) -> int | float:
    """Find max value; supports generators/iterators, not just lists."""
    maksimum = None
    for n in numbers:
        if maksimum is None or n > maksimum:
            maksimum = n
    if maksimum is None:
        raise ValueError("numbers must not be empty")
    return maksimum

