def find_max(numbers, key=lambda x: x):
    """Find max element by a key function, similar to built-in max(key=...)."""
    it = iter(numbers)
    maksimum = next(it)
    for n in it:
        if key(n) > key(maksimum):
            maksimum = n
    return maksimum

