def find_max(numbers):
    """Find max; raises clear error on empty input, O(n) time O(1) space."""
    if not numbers:
        raise ValueError("numbers must not be empty")
    maksimum = numbers[0]
    for n in numbers[1:]:
        maksimum = n if n > maksimum else maksimum
    return maksimum

