def is_palindrome(text: str) -> bool:
    """Check palindrome using two-pointer over a generator, O(1) extra space aside from filtering."""
    chars = [c.lower() for c in text if c.isalnum()]
    return all(chars[i] == chars[~i] for i in range(len(chars) // 2))

