def is_palindrome(text: str) -> bool:
    """Check palindrome; cached for repeated calls with the same input."""
    return _is_palindrome_cached(text.lower())

@lru_cache(maxsize=256)
def _is_palindrome_cached(cleaned_lower_text: str) -> bool:
    s = "".join(c for c in cleaned_lower_text if c.isalnum())
    return s == s[::-1]

