def bubble_sort(arr):
    panjang = len(arr)
    for i in range(panjang):
        tertukar = False
        for j in range(panjang-1):
            if arr[j] > arr[j+1]:
                arr[j], arr[j+1] = arr[j+1], arr[j]
                tertukar = True
        if tertukar == False:
            break
    return arr

print("[3,1,4,2] menjadi", bubble_sort([3,1,4,2]))

