def urutkan(data):
    """Mengurutkan list angka ascending dengan algoritma selection sort."""
    hasil = data.copy()
    for i in range(len(hasil)):
        idx_min = i
        for j in range(i+1, len(hasil)):
            if hasil[j] < hasil[idx_min]:
                idx_min = j
        hasil[i], hasil[idx_min] = hasil[idx_min], hasil[i]
    return hasil

