def urutkan(data: List[float], algoritma: str = "bubble") -> List[float]:
    """Mengurutkan list ascending dengan pilihan algoritma.

    Args:
        data: List angka yang akan diurutkan.
        algoritma: 'bubble' atau 'builtin', menentukan metode yang dipakai.

    Returns:
