        raise TypeError("data harus berupa list")
    if algoritma == "builtin":
        return sorted(data)
    hasil = data.copy()
    n = len(hasil)
    for i in range(n - 1):
        tertukar = False
        for j in range(n - 1 - i):
            if hasil[j] > hasil[j + 1]:
                hasil[j], hasil[j + 1] = hasil[j + 1], hasil[j]
                tertukar = True
        if not tertukar:
            break
    return hasil


