from typing import List

def urutkan(data: List[float]) -> List[float]:
    """Mengurutkan list ascending dengan insertion sort (validasi lengkap)."""
    if not isinstance(data, list):
        raise TypeError("data harus berupa list")
    if not all(isinstance(x, (int, float)) for x in data):
        raise TypeError("semua elemen harus berupa angka")
    hasil = data.copy()
    for i in range(1, len(hasil)):
        kunci = hasil[i]
        j = i - 1
        while j >= 0 and hasil[j] > kunci:
            hasil[j + 1] = hasil[j]
            j -= 1
        hasil[j + 1] = kunci
    return hasil


