def linear_search(daftar: list[str], target: str) -> tuple[int, int]:
    """Mencari target secara sekuensial. Return (indeks atau -1, jumlah perbandingan)."""
    for i, nama in enumerate(daftar, start=1):
        if daftar[i - 1] == target:
            return i - 1, i
    return -1, len(daftar)


def binary_search(daftar: list[str], target: str) -> tuple[int, int]:
    """Mencari target pada data terurut dengan membagi dua rentang tiap iterasi."""
    kiri, kanan, perbandingan = 0, len(daftar) - 1, 0
    while kiri <= kanan:
        perbandingan += 1
        tengah = (kiri + kanan) // 2
        if daftar[tengah] == target:
            return tengah, perbandingan
        if daftar[tengah] < target:
            kiri = tengah + 1
        else:
            kanan = tengah - 1
    return -1, perbandingan


def bandingkan(daftar: list[str], target: str) -> None:
    """Membandingkan hasil dan efisiensi Linear Search vs Binary Search."""
    daftar_urut = sorted(daftar)
    idx_l, cmp_l = linear_search(daftar, target)
    idx_b, cmp_b = binary_search(daftar_urut, target)
    print(f"Linear Search -> indeks {idx_l}, {cmp_l} perbandingan")
    print(f"Binary Search -> indeks {idx_b}, {cmp_b} perbandingan (pada data terurut)")
    lebih_baik = "Binary Search" if cmp_b < cmp_l else "Linear Search"
    print(f"Untuk kasus ini, {lebih_baik} lebih sedikit perbandingannya.")
    print("Linear Search cocok untuk data kecil/tidak terurut; Binary Search unggul untuk data besar & terurut.")


