    """Mencari target secara sekuensial -- O(n)."""
    for i, nama in enumerate(daftar):
        if nama == target:
            return HasilPencarian(i, i + 1)
    return HasilPencarian(-1, len(daftar))


def binary_search(daftar: list[str], target: str) -> HasilPencarian:
    """Mencari target pada data terurut dengan divide & conquer -- O(log n)."""
    kiri, kanan, perbandingan = 0, len(daftar) - 1, 0
    while kiri <= kanan:
        perbandingan += 1
        tengah = (kiri + kanan) // 2
        if daftar[tengah] == target:
            return HasilPencarian(tengah, perbandingan)
        if daftar[tengah] < target:
            kiri = tengah + 1
        else:
            kanan = tengah - 1
    return HasilPencarian(-1, perbandingan)


