from typing import Callable, Dict

class SchoolChatbot:
    """Chatbot kata kunci untuk FAQ sekolah, mudah diperluas via register()."""

    def __init__(self, exit_word: str = "keluar", exit_message: str = "Sampai jumpa!"):
        self._handlers: Dict[str, str] = {}
        self._exit_word = exit_word
        self._exit_message = exit_message

    def register(self, keyword: str, response: str) -> "SchoolChatbot":
        self._handlers[keyword.lower()] = response
        return self

    def _respond(self, text: str) -> str:
        return self._handlers.get(text.strip().lower(), "Maaf, saya tidak mengerti")

    def run(self, input_fn: Callable[[], str] = input) -> None:
        while True:
            q = input_fn()
            if q.strip().lower() == self._exit_word:
                print(self._exit_message)
                return
            print(self._respond(q))


