from typing import TypeVar, Iterable, List, Callable

T = TypeVar("T", int, float)

def apply_to_all(fn: Callable[[T], T], items: Iterable[T]) -> List[T]:
    """Terapkan fungsi `fn` ke setiap elemen `items`, kembalikan list baru."""
    return list(map(fn, items))


def kuadrat_list(lst: Iterable[T]) -> List[T]:
    """Kuadratkan tiap elemen menggunakan lambda, dibangun di atas apply_to_all generik."""
    return apply_to_all(lambda x: x * x, lst)


