from typing import Protocol, Iterable, runtime_checkable

@runtime_checkable
class SupportsSquareAndAdd(Protocol):
    def __mul__(self, other): ...
    def __add__(self, other): ...

def jumlah_kuadrat(lst: Iterable[SupportsSquareAndAdd]):
    """Jumlah kuadrat untuk tipe data apapun yang mendukung __mul__ dan __add__ (duck typing)."""
    total = None
    for x in lst:
        kuadrat = x * x
        total = kuadrat if total is None else total + kuadrat
    return total if total is not None else 0


