def urutkan_alfabet_manual(daftar):
    """Implementasi merge sort manual sebagai pembanding, O(n log n)."""
    if len(daftar) <= 1:
        return daftar
    mid = len(daftar) // 2
    kiri = urutkan_alfabet_manual(daftar[:mid])
    kanan = urutkan_alfabet_manual(daftar[mid:])
    hasil, i, j = [], 0, 0
    while i < len(kiri) and j < len(kanan):
        if kiri[i] <= kanan[j]:
            hasil.append(kiri[i]); i += 1
        else:
            hasil.append(kanan[j]); j += 1
    return hasil + kiri[i:] + kanan[j:]


