def acak_array(arr):
    """Shuffle non-destructive dengan validasi tipe dan penanganan array kosong/satu elemen."""
    if not isinstance(arr, (list, tuple)):
        raise TypeError(f"Diharapkan list/tuple, diterima {type(arr).__name__}")
