from enum import Enum
from typing import Union

class Operator(Enum):
    TAMBAH = "+"
    KURANG = "-"
    KALI = "*"
    BAGI = "/"

def kalkulator(a: float, b: float, op: str) -> float:
    """Hitung hasil operasi a dan b berdasarkan simbol op."""
    try:
        operator = Operator(op)
    except ValueError:
        raise ValueError(f"Operator '{op}' tidak dikenali") from None

    if operator is Operator.TAMBAH:
        return a + b
    if operator is Operator.KURANG:
        return a - b
    if operator is Operator.KALI:
        return a * b
    if b == 0:
        raise ZeroDivisionError("Pembagi tidak boleh nol")
    return a / b

