def kalkulator(a: float, b: float, op: str) -> float:
    """
    Menghitung hasil operasi aritmatika dasar.

    Args:
        a: bilangan pertama.
        b: bilangan kedua.
        op: salah satu dari '+', '-', '*', '/'.

    Raises:
        ValueError: jika op tidak dikenali.
        ZeroDivisionError: jika op '/' dan b == 0.
    """
    if op == "+":
        return a + b
    if op == "-":
        return a - b
    if op == "*":
        return a * b
    if op == "/":
        if b == 0:
            raise ZeroDivisionError("Pembagi tidak boleh nol")
        return a / b
    raise ValueError(f"Operator '{op}' tidak dikenali")


def main() -> None:
    try:
        a = float(input("Angka pertama: "))
        b = float(input("Angka kedua: "))
        op = input("Operator (+, -, *, /): ").strip()
        print(f"Hasil: {kalkulator(a, b, op)}")
    except ValueError as e:
        print(f"Input tidak valid: {e}")
    except ZeroDivisionError as e:
        print(f"Error: {e}")


if __name__ == "__main__":
    main()

