class ZeroDivisionInputError(Exception):
    """Exception khusus saat pembagi bernilai nol."""

def kalkulator(a: float, b: float, op: str) -> float:
    """Hitung operasi dasar a dan b, melempar exception kustom bila perlu."""
    operasi_valid = {"+", "-", "*", "/"}
    if op not in operasi_valid:
        raise ValueError(f"Operator '{op}' tidak dikenali")
    if op == "/" and b == 0:
        raise ZeroDivisionInputError("Pembagi tidak boleh nol")
    return {"+": a + b, "-": a - b, "*": a * b, "/": a / b if b else 0}[op]

