from decimal import Decimal, InvalidOperation

def kalkulator(a: Decimal, b: Decimal, op: str) -> Decimal:
    """Hitung a op b menggunakan Decimal untuk presisi desimal yang akurat."""
    ops = {"+": a + b, "-": a - b, "*": a * b}
