from typing import Callable, Dict

def buat_kalkulator() -> Callable[[float, float, str], float]:
    """Factory yang mengembalikan fungsi kalkulator dengan operasi tertutup (closure)."""
    operasi: Dict[str, Callable[[float, float], float]] = {
        "+": lambda a, b: a + b,
        "-": lambda a, b: a - b,
        "*": lambda a, b: a * b,
        "/": lambda a, b: a / b,
    }

    def hitung(a: float, b: float, op: str) -> float:
        if op not in operasi:
            raise ValueError(f"Operator '{op}' tidak dikenali")
        if op == "/" and b == 0:
            raise ZeroDivisionError("Pembagi tidak boleh nol")
        return operasi[op](a, b)

    return hitung


