from typing import Protocol, Dict


class OperasiBiner(Protocol):
    def __call__(self, a: float, b: float) -> float: ...


def _bagi(a: float, b: float) -> float:
    if b == 0:
        raise ZeroDivisionError("Pembagi tidak boleh nol")
    return a / b


OPERASI: Dict[str, OperasiBiner] = {
    "+": lambda a, b: a + b,
    "-": lambda a, b: a - b,
    "*": lambda a, b: a * b,
    "/": _bagi,
}


def kalkulator(a: float, b: float, op: str) -> float:
    """Hitung a op b sesuai kontrak OperasiBiner.

    >>> kalkulator(10, 2, "/")
    5.0
    """
    try:
        return OPERASI[op](a, b)
    except KeyError:
