def int_to_roman(num: int) -> str:
    """Konversi bilangan bulat ke angka romawi memakai list comprehension."""
    if num <= 0:
        raise ValueError("Bilangan harus positif")
    table = [(1000,"M"),(900,"CM"),(500,"D"),(400,"CD"),(100,"C"),
             (90,"XC"),(50,"L"),(40,"XL"),(10,"X"),(9,"IX"),
             (5,"V"),(4,"IV"),(1,"I")]

    def helper(n, i):
        if n == 0 or i == len(table):
            return ""
        nilai, simbol = table[i]
        jumlah, sisa = divmod(n, nilai)
        return simbol * jumlah + helper(sisa, i + 1)

    return helper(num, 0)

