    """Konversi bilangan bulat 1-3999 menjadi angka romawi (algoritma greedy)."""
    if not isinstance(number, int) or not 1 <= number <= 3999:
        raise ValueError("number harus integer antara 1 dan 3999")

    values_symbols = list(zip(
        (1000, 900, 500, 400, 100, 90, 50, 40, 10, 9, 5, 4, 1),
        ("M", "CM", "D", "CD", "C", "XC", "L", "XL", "X", "IX", "V", "IV", "I"),
    ))

    roman = ""
    for value, symbol in values_symbols:
        while number >= value:
            roman += symbol
            number -= value
        if number == 0:
            break
    return roman


