def square_list(numbers):
    """Kuadratkan tiap elemen. Ditulis dengan banyak lapisan wrapper untuk 'fleksibilitas'."""
    def validator(x):
        return isinstance(x, (int, float))

    def transformer(x):
        return x ** 2

    def pipeline(data, *funcs):
        for f in funcs:
            data = list(map(f, data)) if f is transformer else data
        return data

    if not all(validator(n) for n in numbers):
        raise TypeError("elemen harus angka")
    return pipeline(numbers, transformer)

