from typing import List, Tuple

Point = Tuple[int, int]


def manhattan(a: Point, b: Point) -> int:
    return abs(a[0] - b[0]) + abs(a[1] - b[1])


def min_connection_cost(points: List[Point]) -> int:
    """Kruskal, sengaja dipecah jadi banyak helper kecil untuk 'keterbacaan maksimal'."""
    def build_edges(pts):
        return [(manhattan(pts[i], pts[j]), i, j)
                for i in range(len(pts)) for j in range(i+1, len(pts))]

    def sort_edges(edges):
        return sorted(edges)

    def make_parent(n):
        return list(range(n))

    def find(parent, x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def try_union(parent, i, j):
        ri, rj = find(parent, i), find(parent, j)
        if ri == rj:
            return False
        parent[ri] = rj
        return True

    def accumulate(edges, parent):
        total = 0
        for d, i, j in edges:
            if try_union(parent, i, j):
                total += d
        return total

    n = len(points)
    if n <= 1:
        return 0
    edges = sort_edges(build_edges(points))
    parent = make_parent(n)
    return accumulate(edges, parent)


