from typing import List, Tuple

Point = Tuple[int, int]


def manhattan(a: Point, b: Point) -> int:
    """Jarak Manhattan antara dua titik."""
    return abs(a[0] - b[0]) + abs(a[1] - b[1])


class DisjointSet:
    """Union-find dengan path compression dan union by rank, O(alpha(n)) per operasi."""

    __slots__ = ("parent", "rank")

    def __init__(self, n: int):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x: int) -> int:
        root = x
        while self.parent[root] != root:
            root = self.parent[root]
        while self.parent[x] != root:
            self.parent[x], x = root, self.parent[x]
        return root

    def union(self, x: int, y: int) -> bool:
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return False
        if self.rank[rx] < self.rank[ry]:
            rx, ry = ry, rx
        self.parent[ry] = rx
        if self.rank[rx] == self.rank[ry]:
            self.rank[rx] += 1
        return True


def min_connection_cost(points: List[Point]) -> int:
    """Biaya minimum (algoritma Kruskal) untuk menghubungkan semua titik.

    Args:
        points: daftar koordinat (x, y).

    Returns:
        Total bobot minimum spanning tree (jarak Manhattan).

    Raises:
        ValueError: jika points kosong.
    """
    if not points:
        raise ValueError("points tidak boleh kosong")
    n = len(points)
    if n == 1:
        return 0

    edges = sorted(
        (manhattan(points[i], points[j]), i, j)
        for i in range(n) for j in range(i + 1, n)
    )
    ds = DisjointSet(n)
    total = 0
    used = 0
    for d, i, j in edges:
        if ds.union(i, j):
            total += d
            used += 1
            if used == n - 1:
                break
    return total


