from typing import List, Tuple, Iterator

Point = Tuple[int, int]


def manhattan(a: Point, b: Point) -> int:
    return abs(a[0] - b[0]) + abs(a[1] - b[1])


def _all_edges(points: List[Point]) -> Iterator[Tuple[int, int, int]]:
    """Generator seluruh edge (bobot, i, j) dari graf lengkap titik-titik."""
    n = len(points)
    for i in range(n):
        for j in range(i + 1, n):
            yield manhattan(points[i], points[j]), i, j


def min_connection_cost(points: List[Point]) -> int:
    """Kruskal: hasil dijamin sama untuk permutasi urutan titik apa pun (MST invariant)."""
    n = len(points)
    if n <= 1:
        return 0
    parent = list(range(n))

    def find(x: int) -> int:
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    total = 0
    used = 0
    for d, i, j in sorted(_all_edges(points)):
        ri, rj = find(i), find(j)
        if ri != rj:
            parent[ri] = rj
            total += d
            used += 1
            if used == n - 1:
                break
    return total


