@dataclass
class MST:
    """Hasil perhitungan minimum spanning tree: total biaya dan edge terpilih."""
    total_cost: int
    edges_used: List[Tuple[int, int, int]] = field(default_factory=list)


def compute_mst(points: List[Point]) -> MST:
    """Kruskal, mengembalikan objek MST berisi total biaya dan daftar edge yang dipakai."""
    n = len(points)
    if n <= 1:
        return MST(total_cost=0)
    parent = list(range(n))

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    edges = sorted(
        (manhattan(points[i], points[j]), i, j)
        for i in range(n) for j in range(i + 1, n)
    )
    result = MST(total_cost=0)
    for d, i, j in edges:
        ri, rj = find(i), find(j)
        if ri != rj:
            parent[ri] = rj
            result.total_cost += d
            result.edges_used.append((d, i, j))
    return result


