        d_sekarang, node = heapq.heappop(antrian)
        for tetangga, bobot in graf[node].items():
            baru = d_sekarang + bobot
            if baru < jarak[tetangga]:
                jarak[tetangga] = baru
                heapq.heappush(antrian, (baru, tetangga))
    return jarak


