from typing import Dict

def dijkstra(graf: Dict[str, Dict[str, int]], mulai: str) -> Dict[str, float]:
    """
    Menghitung jarak terpendek dari `mulai` ke semua simpul pada graf
    berbobot non-negatif menggunakan algoritma Dijkstra + min-heap.
    """
    jarak = {node: float('inf') for node in graf}
    jarak[mulai] = 0
    visited = set()
    heap = [(0, mulai)]

    while heap:
        d_now, node = heapq.heappop(heap)
        if node in visited:
            continue
        visited.add(node)
        for tetangga, bobot in graf.get(node, {}).items():
            baru = d_now + bobot
            if baru < jarak[tetangga]:
                jarak[tetangga] = baru
                heapq.heappush(heap, (baru, tetangga))
    return jarak


