def dijkstra(graph: Dict[str, Dict[str, float]], start: str) -> Dict[str, float]:
    """Jarak terpendek dari `start` ke semua simpul (algoritma Dijkstra).

    Args:
        graph: adjacency dict, mis. {'A': {'B': 4}}.
        start: simpul awal.

    Returns:
        Dict simpul -> jarak terpendek (inf jika tidak terjangkau).

    Raises:
        ValueError: jika ada bobot negatif.
    """
    for u in graph:
        for v, w in graph[u].items():
            if w < 0:
                raise ValueError(f"Bobot negatif tidak didukung: {u}->{v}")

    dist = {node: float('inf') for node in graph}
    dist[start] = 0
    visited = set()
    heap = [(0, start)]

    while heap:
        d_u, u = heapq.heappop(heap)
        if u in visited:
            continue
        visited.add(u)
        for v, w in graph.get(u, {}).items():
            nd = d_u + w
            if nd < dist.get(v, float('inf')):
                dist[v] = nd
                heapq.heappush(heap, (nd, v))
    return dist


if __name__ == "__main__":
    graf = {'A': {'B': 4, 'C': 2}, 'B': {'C': 1, 'D': 5},
           'C': {'D': 8, 'E': 10}, 'D': {'E': 2}, 'E': {}}
    hasil = dijkstra(graf, 'A')
    print(hasil)

