import heapq
from typing import Dict, Hashable


def algoritma_dijkstra(graph: Dict[Hashable, Dict[Hashable, float]],
        start: Hashable) -> Dict[Hashable, float]:
    """Shortest paths from `start` to every node (Dijkstra, O((V+E) log V)).

    >>> g = {'A': {'B': 4, 'C': 2}, 'B': {'C': 1, 'D': 5},
    ...      'C': {'D': 8, 'E': 10}, 'D': {'E': 2}, 'E': {}}
    >>> algoritma_dijkstra(g, 'A')
    {'A': 0, 'B': 4, 'C': 2, 'D': 9, 'E': 11}
    """
    if any(w < 0 for edges in graph.values() for w in edges.values()):
        raise ValueError("Algoritma Dijkstra tidak mendukung bobot negatif")

    dist: Dict[Hashable, float] = {node: float('inf') for node in graph}
    dist[start] = 0
    seen = set()
    heap: list = [(0, start)]

    while heap:
        d_u, u = heapq.heappop(heap)
        if u in seen:
            continue
        seen.add(u)
        for v, w in graph.get(u, {}).items():
            nd = d_u + w
            if nd < dist.get(v, float('inf')):
                dist[v] = nd
                heapq.heappush(heap, (nd, v))
    return {k: (int(v) if v != float('inf') and v == int(v) else v) for k, v in dist.items()}


