    n = len(bobot)
    tabel = []
    for i in range(n+1):
        baris = []
        for j in range(kapasitas+1):
            baris.append(0)
        tabel.append(baris)

    for i in range(1, n+1):
        for j in range(0, kapasitas+1):
            if bobot[i-1] <= j:
                ambil = nilai[i-1] + tabel[i-1][j-bobot[i-1]]
                tidak_ambil = tabel[i-1][j]
                if ambil > tidak_ambil:
                    tabel[i][j] = ambil
                else:
                    tabel[i][j] = tidak_ambil
            else:
                tabel[i][j] = tabel[i-1][j]
    return tabel[n][kapasitas]

