from typing import List


def knapsack(weights: List[int], values: List[int], capacity: int) -> int:
    """Solve 0/1 Knapsack with DP, O(n*capacity) time, O(capacity) space.

    >>> knapsack([10, 20, 30], [60, 100, 120], 50)
    220
    """
    if len(weights) != len(values):
        raise ValueError("weights dan values harus sama panjang")
    if capacity < 0:
        raise ValueError("capacity tidak boleh negatif")

    dp = [0] * (capacity + 1)
    for w_i, v_i in zip(weights, values):
        for cap in range(capacity, w_i - 1, -1):
            dp[cap] = max(dp[cap], v_i + dp[cap - w_i])
    return dp[capacity]


