def solve_sudoku(board):
    kosong = None
    for i in range(9):
        for j in range(9):
            if board[i][j] == 0:
                kosong = (i, j)
                break
        if kosong != None:
            break
    if kosong == None:
        return True

    r, c = kosong
    for angka in range(1, 10):
        boleh = True
        for x in range(9):
            if board[r][x] == angka:
                boleh = False
            if board[x][c] == angka:
                boleh = False
        bx = (c // 3) * 3
        by = (r // 3) * 3
        for i in range(by, by+3):
            for j in range(bx, bx+3):
                if board[i][j] == angka:
                    boleh = False
        if boleh == True:
            board[r][c] = angka
            if solve_sudoku(board):
                return True
            board[r][c] = 0
    return False

